// frontend/src/components/Dashboard/AccountBalance.js
import React, { useState, useEffect } from 'react';
import {
  Paper,
  Typography,
  Box,
  Skeleton,
  List,
  ListItem,
  ListItemText,
  Divider,
  Chip,
  useTheme,
  CircularProgress,
  Fade
} from '@mui/material';
import {
  AccountBalance as AccountBalanceIcon,
  TrendingUp,
  TrendingDown,
  Lock,
  LockOpen,
  Schedule
} from '@mui/icons-material';

const AccountBalance = ({ balance, loading }) => {
  const theme = useTheme();
  const [progress, setProgress] = useState(0);
  const [isUpdating, setIsUpdating] = useState(false);

  // Timer visual de 30 segundos
  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(0);
      setIsUpdating(true);

      // Animação do progresso
      const progressInterval = setInterval(() => {
        setProgress(prev => {
          if (prev >= 100) {
            clearInterval(progressInterval);
            setIsUpdating(false);
            return 0;
          }
          return prev + (100 / 300); // 30 segundos = 300 décimos
        });
      }, 100); // Atualiza a cada 100ms

      return () => clearInterval(progressInterval);
    }, 30000); // 30 segundos

    return () => clearInterval(interval);
  }, []);

  const formatCurrency = (value, currency = 'USDT') => {
    if (value === null || value === undefined) return `0.00 ${currency}`;
    return `${parseFloat(value).toFixed(2)} ${currency}`;
  };

  const formatNumber = (value) => {
    if (value === null || value === undefined) return '0.00';
    return parseFloat(value).toFixed(2);
  };

  if (loading) {
    return (
      <Paper sx={{ p: 2.5, height: 380 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
          <Skeleton variant="circular" width={20} height={20} sx={{ mr: 1 }} />
          <Skeleton variant="text" width={120} height={24} />
        </Box>
        <Box sx={{ mb: 1.5 }}>
          <Skeleton variant="text" width={80} height={16} />
          <Skeleton variant="text" width={100} height={32} />
        </Box>
        <Divider sx={{ my: 1.5 }} />
        {Array.from({ length: 3 }).map((_, index) => (
          <Box key={index} sx={{ mb: 1.5 }}>
            <Skeleton variant="text" width={70} height={14} />
            <Skeleton variant="text" width={90} height={20} />
          </Box>
        ))}
      </Paper>
    );
  }

  if (!balance) {
    return (
      <Paper sx={{ p: 2.5, height: 380 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, fontSize: '1.1rem' }}>
          <AccountBalanceIcon color="primary" sx={{ fontSize: 20 }} />
          Saldo da Conta
        </Typography>
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            height: 280,
            bgcolor: 'background.default',
            borderRadius: 1,
            border: `1px dashed ${theme.palette.divider}`
          }}
        >
          <Typography variant="body2" color="text.secondary">
            Erro ao carregar saldo
          </Typography>
        </Box>
      </Paper>
    );
  }

  // Verificar se balance.data existe e tem api_configured
  const balanceData = balance.data || balance;

  if (!balanceData?.api_configured) {
    return (
      <Paper sx={{ p: 2.5, height: 380 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, fontSize: '1.1rem' }}>
          <AccountBalanceIcon color="primary" sx={{ fontSize: 20 }} />
          Saldo da Conta
        </Typography>
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            height: 280,
            bgcolor: 'background.default',
            borderRadius: 1,
            border: `1px dashed ${theme.palette.divider}`,
            p: 2
          }}
        >
          <Lock sx={{ fontSize: 40, color: 'text.secondary', mb: 1.5 }} />
          <Typography variant="subtitle1" color="text.secondary" gutterBottom sx={{ fontSize: '1rem' }}>
            API Bitget não configurada
          </Typography>
          <Typography variant="body2" color="text.secondary" align="center" sx={{ fontSize: '0.85rem' }}>
            Configure suas credenciais da API Bitget nas configurações para visualizar o saldo da conta e sincronizar operações.
          </Typography>
        </Box>
      </Paper>
    );
  }

  const totalEquity = parseFloat(balanceData.total_balance || 0);
  const availableBalance = parseFloat(balanceData.available_balance || 0);
  const unrealizedPnl = parseFloat(balanceData.unrealized_pnl || 0);
  const marginRatio = parseFloat(balanceData.margin_ratio || 0);
  const frozenBalance = totalEquity - availableBalance; // Calcular saldo bloqueado
  const apiConfigured = balanceData.api_configured || false;

  const balanceItems = [
    {
      label: 'Saldo Disponível',
      value: formatCurrency(availableBalance),
      description: 'Valor disponível para novas operações',
      color: 'success.main',
      icon: <LockOpen />
    },
    {
      label: 'Saldo Bloqueado',
      value: formatCurrency(frozenBalance),
      description: 'Valor usado como margem em posições abertas',
      color: 'warning.main',
      icon: <Lock />
    },
    {
      label: 'PnL Não Realizado',
      value: formatCurrency(unrealizedPnl),
      description: 'Lucro/prejuízo das posições abertas',
      color: unrealizedPnl >= 0 ? 'success.main' : 'error.main',
      icon: unrealizedPnl >= 0 ? <TrendingUp /> : <TrendingDown />
    }
  ];

  const getMarginRiskLevel = (ratio) => {
    if (ratio >= 80) return { color: 'error', label: 'Alto Risco' };
    if (ratio >= 60) return { color: 'warning', label: 'Risco Médio' };
    if (ratio >= 40) return { color: 'info', label: 'Risco Baixo' };
    return { color: 'success', label: 'Seguro' };
  };

  const marginRisk = getMarginRiskLevel(marginRatio);

  return (
    <Fade in={true} timeout={500}>
      <Paper sx={{ p: 2.5, height: 380, transition: 'all 0.3s ease-in-out' }}>
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, fontSize: '1.1rem' }}>
          <AccountBalanceIcon color="primary" sx={{ fontSize: 20 }} />
          Saldo da Conta
        </Typography>

        {/* Timer Visual */}
          <Box sx={{ position: 'relative', display: 'inline-flex' }}>
            <CircularProgress
              variant="determinate"
              value={progress}
              size={24}
              thickness={4}
              sx={{
                color: theme.palette.primary.main,
                '& .MuiCircularProgress-circle': {
                  strokeLinecap: 'round',
                }
              }}
            />
            <Box
              sx={{
                top: 0,
                left: 0,
                bottom: 0,
                right: 0,
                position: 'absolute',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              <Schedule sx={{ fontSize: 12, color: theme.palette.primary.main }} />
            </Box>
          </Box>
      </Box>

      {/* Patrimônio Total em destaque */}
      <Box sx={{ mb: 2, textAlign: 'center' }}>
        <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.75rem' }}>
          Patrimônio Total
        </Typography>
        <Typography
          variant="h4"
          sx={{
            fontWeight: 'bold',
            color: 'primary.main',
            mb: 0.5,
            fontSize: '1.8rem'
          }}
        >
          {formatCurrency(totalEquity)}
        </Typography>

        {/* Indicador de margem */}
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 0.5 }}>
          <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.7rem' }}>
            Margem:
          </Typography>
          <Chip
            label={`${formatNumber(marginRatio)}%`}
            color={marginRisk.color}
            size="small"
            sx={{ fontWeight: 'bold', fontSize: '0.7rem', height: 20 }}
          />
          <Typography variant="caption" color={`${marginRisk.color}.main`} sx={{ fontSize: '0.7rem' }}>
            {marginRisk.label}
          </Typography>
        </Box>
      </Box>

      <Divider sx={{ mb: 1.5 }} />

      {/* Lista de saldos */}
      <List dense sx={{ p: 0 }}>
        {balanceItems.map((item, index) => (
          <ListItem key={index} sx={{ px: 0, py: 0.5 }}>
            <Box
              sx={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                width: 28,
                height: 28,
                borderRadius: '50%',
                bgcolor: `${item.color}20`,
                mr: 1.5
              }}
            >
              {React.cloneElement(item.icon, {
                sx: { color: item.color, fontSize: 14 }
              })}
            </Box>
            <ListItemText
              primary={
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <Typography variant="body2" sx={{ fontWeight: 500, fontSize: '0.85rem' }}>
                    {item.label}
                  </Typography>
                  <Typography
                    variant="body2"
                    sx={{
                      fontWeight: 'bold',
                      color: item.color,
                      fontSize: '0.85rem'
                    }}
                  >
                    {item.value}
                  </Typography>
                </Box>
              }
              secondary={
                <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.7rem' }}>
                  {item.description}
                </Typography>
              }
            />
          </ListItem>
        ))}
      </List>

      {/* Aviso de margem se necessário */}
      {marginRatio >= 60 && (
        <Box sx={{ mt: 1.5 }}>
          <Chip
            label="⚠️ Atenção ao nível de margem"
            color="warning"
            size="small"
            sx={{ width: '100%', fontSize: '0.7rem', height: 24 }}
          />
        </Box>
      )}
      </Paper>
    </Fade>
  );
};

export default AccountBalance;
